import { useState } from "react";
import { motion } from "framer-motion";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import FAQItem from "@/components/FAQItem";

const FAQS = [
  { q: "How do you calculate the volume of a sphere?", a: "The volume of a sphere is V = (4/3) x pi x r^3, where r is the radius. Cube the radius, multiply by pi, then multiply by 4/3. For example, a sphere with radius 3 has volume (4/3) x pi x 27 = 113.10 cubic units." },
  { q: "What is the formula for the volume of a cylinder?", a: "The volume of a cylinder is V = pi x r^2 x h. First calculate the circular base area with pi x radius squared, then multiply by the height. A cylinder with radius 4 and height 10 has volume pi x 16 x 10 = 502.65 cubic units." },
  { q: "How do you find the volume of a rectangular prism?", a: "Multiply length x width x height. The rectangular prism formula is V = l x w x h. If a box is 8 units long, 5 units wide, and 3 units tall, its volume is 8 x 5 x 3 = 120 cubic units." },
  { q: "What is the difference between volume and surface area?", a: "Volume measures the three-dimensional space inside a shape and is expressed in cubic units. Surface area measures the total outside area covering the shape and is expressed in square units. A box can have a large surface area but a smaller volume depending on its proportions." },
  { q: "How do you calculate the volume of a cone?", a: "The volume of a cone is V = (1/3) x pi x r^2 x h. It is one third of a cylinder with the same radius and height. For radius 3 and height 12, volume = (1/3) x pi x 9 x 12 = 113.10 cubic units." },
];

type Shape = "cube" | "rectangular" | "sphere" | "cylinder" | "cone" | "pyramid";

export default function VolumeCalculator() {
  const [shape, setShape] = useState<Shape>("rectangular");
  const [side, setSide] = useState(5);
  const [length, setLength] = useState(8);
  const [width, setWidth] = useState(5);
  const [height, setHeight] = useState(4);
  const [radius, setRadius] = useState(3);

  const volume = (() => {
    if (shape === "cube") return side ** 3;
    if (shape === "rectangular") return length * width * height;
    if (shape === "sphere") return (4 / 3) * Math.PI * radius ** 3;
    if (shape === "cylinder") return Math.PI * radius ** 2 * height;
    if (shape === "cone") return (Math.PI * radius ** 2 * height) / 3;
    return (length * width * height) / 3;
  })();

  const formula = {
    cube: "V = side^3",
    rectangular: "V = length x width x height",
    sphere: "V = (4/3) x pi x radius^3",
    cylinder: "V = pi x radius^2 x height",
    cone: "V = (1/3) x pi x radius^2 x height",
    pyramid: "V = (length x width x height) / 3",
  }[shape];

  const inputClass = "w-full px-3 py-2 rounded-xl border border-input bg-background text-foreground text-lg font-bold focus:outline-none focus:ring-2 focus:ring-primary/40 transition-all";
  const field = (id: string, label: string, value: number, setter: (value: number) => void) => (
    <div>
      <label htmlFor={id} className="text-sm font-semibold text-foreground block mb-2">{label}</label>
      <input id={id} type="number" min="0" step="0.01" inputMode="decimal" value={value} onChange={(event) => setter(Number(event.target.value))} className={inputClass} />
    </div>
  );

  return (
    <>
      <SEOHead
        title="Free Volume Calculator Online - Calculate Volume of Any Shape Instantly | CalcHive"
        description="Free online volume calculator. Calculate volume of a cube, sphere, cylinder, cone, rectangular prism and pyramid instantly. 100% free for students and everyone, no signup required."
        canonical="/volume-calculator"
        keywords="free volume calculator, volume calculator online free, calculate volume of shapes free, sphere volume calculator free, cylinder volume calculator free online"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Volume Calculator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free volume calculator to calculate volume of shapes free, including cube, sphere, cylinder, cone, rectangular prism, and pyramid.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="mb-6">
            <label htmlFor="shape" className="text-sm font-semibold text-foreground block mb-2">Shape</label>
            <select id="shape" value={shape} onChange={(event) => setShape(event.target.value as Shape)} className={inputClass}>
              <option value="cube">Cube</option>
              <option value="rectangular">Rectangular Prism</option>
              <option value="sphere">Sphere</option>
              <option value="cylinder">Cylinder</option>
              <option value="cone">Cone</option>
              <option value="pyramid">Pyramid</option>
            </select>
          </div>
          <div className="grid grid-cols-1 sm:grid-cols-2 gap-4 mb-8">
            {shape === "cube" && field("side", "Side length", side, setSide)}
            {shape === "rectangular" && <>{field("length", "Length", length, setLength)}{field("width", "Width", width, setWidth)}{field("height", "Height", height, setHeight)}</>}
            {shape === "sphere" && field("radius", "Radius", radius, setRadius)}
            {(shape === "cylinder" || shape === "cone") && <>{field("radius", "Radius", radius, setRadius)}{field("height", "Height", height, setHeight)}</>}
            {shape === "pyramid" && <>{field("length", "Base length", length, setLength)}{field("width", "Base width", width, setWidth)}{field("height", "Height", height, setHeight)}</>}
          </div>
          <motion.div key={`${shape}-${volume}`} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-1">Volume</p>
              <p className="text-6xl font-black text-white tracking-tight" data-testid="result-volume">{Number.isFinite(volume) ? volume.toFixed(4).replace(/\.?0+$/, "") : "0"}</p>
              <p className="text-white/70 text-sm mt-1">cubic units</p>
            </div>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Calculate Volume of Any Shape for Free</h2>
          <p className="text-muted-foreground leading-relaxed">Select the shape, enter the required dimensions, and the calculator applies the correct volume formula instantly.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground">{formula}</div>
          <h2 className="text-2xl font-bold text-foreground">Volume Formulas for Cube Sphere Cylinder Cone and Pyramid</h2>
          <p className="text-muted-foreground leading-relaxed">Most volume formulas multiply a base area by height. Shapes with curved sides, such as spheres and cones, use pi because their cross sections are circular.</p>
          <h2 className="text-2xl font-bold text-foreground">Free Geometry Volume Tool for Students and Everyone</h2>
          <p className="text-muted-foreground leading-relaxed">This free geometry volume tool works on mobile and desktop for homework, construction estimates, science class, and everyday measurement checks.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map((faq) => <FAQItem key={faq.q} q={faq.q} a={faq.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/volume-calculator" headingLevel="h3" />
      </main>
    </>
  );
}


